package com.eas.ui.user;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class MyOvertimePanel extends UserTablePanel { private final JTextField date=new JTextField(10),hours=new JTextField(6),purpose=new JTextField(32); public MyOvertimePanel(UserSession s){super(s,"My Overtime Requests","SELECT o.id,o.overtime_date,o.requested_hours,o.approved_hours,o.purpose,o.status,o.admin_remarks FROM employees e JOIN overtime_requests o ON e.id=o.employee_id WHERE e.user_id=? ORDER BY o.id DESC","SELECT o.id,o.overtime_date,o.requested_hours,o.approved_hours,o.purpose,o.status,o.admin_remarks FROM employees e JOIN overtime_requests o ON e.id=o.employee_id WHERE e.user_id=? AND (o.status LIKE ? OR o.purpose LIKE ? OR CAST(o.overtime_date AS CHAR) LIKE ?) ORDER BY o.id DESC",true);JPanel p=new JPanel();p.add(new JLabel("OT Date"));p.add(date);p.add(new JLabel("Hours"));p.add(hours);p.add(new JLabel("Purpose"));p.add(purpose);JButton submit=UITheme.button("SUBMIT OVERTIME REQUEST");p.add(submit);add(p,BorderLayout.SOUTH);submit.addActionListener(e->submit());}
 private void submit(){try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement("INSERT INTO overtime_requests(employee_id,overtime_date,requested_hours,purpose) SELECT id,?,?,? FROM employees WHERE user_id=?")){p.setString(1,date.getText().trim());p.setString(2,hours.getText().trim());p.setString(3,purpose.getText().trim());p.setInt(4,session.getId());p.executeUpdate();AuditService.log(session.getId(),"SUBMIT","OVERTIME","Filed overtime request.");load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
